<svg viewBox="0 0 700 620" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Sección 404 de la Clarity Act — Qué Está Prohibido, Permitido y en Disputa</text>
  <g font-family="sans-serif">
    <rect x="30" y="55" width="200" height="130" rx="10" fill="#2a1414" stroke="#f87171" stroke-width="1.3"/>
    <text x="130" y="80" fill="#fca5a5" font-size="14" font-weight="700" text-anchor="middle">Prohibido</text>
    <text x="45" y="105" fill="#e4e4e7" font-size="13">Interés o rendimiento</text>
