    <text x="50" y="410" fill="#71717a" font-size="12">~20 jul 2026 — votación en pleno prevista (requiere 60 votos)</text>

    <rect x="30" y="440" width="640" height="150" rx="10" fill="#1e2a3a" stroke="#60a5fa" stroke-width="1.3"/>
